     * (ISO+offset) string, mismatching the 6 SDKs (Java/Kotlin/C#/Python/
     * Ruby/Elixir) with native LocalDate types.
     */
    public static function toPathDateValue(mixed $value): string
    {
        if ($value === null) {
            return '';
        }
        if ($value instanceof \DateTimeInterface) {
            return $value->format('Y-m-d');
        }
        if (is_string($value)) {
            return substr($value, 0, 10);
        }
        return self::stringify($value);
    }

    /**
     * Convert a value to a representation suitable for use as a query parameter.
     * For collections, joins using the specified collection format delimiter.
     *
     * @return mixed the query value
     */
    public static function toQueryValue(mixed $value, ?string $collectionFormat = null): mixed
    {
        if ($value === null) {
            return null;
        }

        if (is_array($value)) {
            $items = array_map(self::stringify(...), $value);
            return match ($collectionFormat) {
                'ssv' => implode(' ', $items),
                'tsv' => implode("\t", $items),
                'pipes' => implode('|', $items),
                'multi' => $items,
                default => implode(',', $items), // csv or default
            };
        }

        return self::stringify($value);
    }

    /**
     * Convert a value to a string suitable for use as an HTTP header value.
     */
    public static function toHeaderValue(mixed $value): string
    {
        if (is_array($value)) {
            return implode(',', array_map(self::stringify(...), $value));
        }

        return self::stringify($value);
    }

    /**
     * Convert a value to a string suitable for use as an HTTP cookie value.
     * Cookie values follow the same encoding rules as header values.
     *
     * @param mixed $value the value to convert
     *
     * @return string string representation
     */
    public static function toCookieValue(mixed $value): string
    {
        return self::toHeaderValue($value);
    }

    /**
     * Resolve a oneOf schema by attempting deserialization against each candidate.
     * Each candidate is a closure that accepts the raw data and returns a
     * deserialized value, or throws on failure.
     *
     * @param mixed               $data       the data to match
     * @param array<callable>     $candidates list of deserializer closures
     *
     * @return mixed the first successfully deserialized value
     *
     * @throws \UnexpectedValueException when the data matches none of the
     *         candidate schemas. Throws rather than returning null so that
     *         shape-mismatch bugs surface loudly — aligns with Python,
     *         Swift, Dart, Go, Rust (5 of 12 already throw).
     */
    public static function resolveOneOf(mixed $data, array $candidates): mixed
    {
        foreach ($candidates as $candidate) {
            try {
                return $candidate($data);
            } catch (\Throwable) {
                continue;
            }
        }
        throw new \UnexpectedValueException(
            'JSON did not match any schema in the oneOf/anyOf union'
        );
    }

    /**
     * Resolve an anyOf schema by attempting deserialization against each candidate.
     * Each candidate is a closure that accepts the raw data and returns a
     * deserialized value, or throws on failure.
     *
     * @param mixed               $data       the data to match
     * @param array<callable>     $candidates list of deserializer closures
     *
     * @return mixed the first successfully deserialized value, or null if none match
     */
    public static function resolveAnyOf(mixed $data, array $candidates): mixed
    {
        return self::resolveOneOf($data, $candidates);
    }

    /**
     * Qualify an unqualified model class name with the model namespace.
     * Primitive types (string, int, etc.) and already-qualified names are returned as-is.
     */
    public static function qualifySchemaName(string $schema): string
    {
        if (str_contains($schema, '\\') || !preg_match('/^[A-Z]/', $schema)) {
            return $schema;
        }
        $fqcn = 'Zitadel\Client\Models\\' . $schema;
        return class_exists($fqcn) ? $fqcn : $schema;
    }

    /**
     * 2.1 — Decode an OAS `format: byte` field value to its raw binary string.
     * Returns null for null/empty input. Invalid base64 returns null rather
     * than throwing so partially-populated payloads stay readable.
     *
     * The wire form for `format: byte` is a base64-encoded string; SDK users
     * call this helper to recover the underlying bytes.
     */
    public static function decodeBytes(?string $encoded): ?string
    {
        if ($encoded === null || $encoded === '') {
            return null;
        }
        $decoded = base64_decode($encoded, true);
        return $decoded === false ? null : $decoded;
    }

    /**
     * 2.1 — Encode raw bytes as a base64 string suitable for an OAS
     * `format: byte` field. Returns null for null input.
     */
    public static function encodeBytes(?string $raw): ?string
    {
        if ($raw === null) {
            return null;
        }
        return base64_encode($raw);
    }

    /**
     * 4.8: format a \DateInterval as a protobuf-JSON duration string.
     *
     * google.protobuf.Duration is encoded as the number of seconds followed
     * by an "s" suffix (e.g. "3600s"); fractional seconds are written as a
     * decimal with 3, 6, or 9 digits — the smallest precision that preserves
     * the value (e.g. "3600.000000001s"). google.protobuf.Duration has no
     * month/year components, so the interval's ->y/->m are ignored (protobuf
     * durations never set them); days are folded into seconds. A negative
     * interval (->invert === 1) is prefixed with "-".
     */
    public static function formatProtobufDuration(\DateInterval $interval): string
    {
        $sign = $interval->invert === 1 ? '-' : '';

        $seconds = (((($interval->d * 24) + $interval->h) * 60) + $interval->i) * 60
            + $interval->s;
        /* ->f is fractional seconds in the range [0, 1); scale to nanos and
         * round to the nearest whole nanosecond. */
        $nanos = (int) round($interval->f * 1_000_000_000);
        if ($nanos >= 1_000_000_000) {
            $seconds += intdiv($nanos, 1_000_000_000);
            $nanos %= 1_000_000_000;
        }

        if ($nanos === 0) {
            return $sign . $seconds . 's';
        }

        /* Zero-pad to 9 digits, then trim trailing zeros down to the nearest
         * 3/6/9-digit boundary so the fraction stays a valid protobuf-JSON
         * sub-second value. */
        $frac = str_pad((string) $nanos, 9, '0', STR_PAD_LEFT);
        if (str_ends_with($frac, '000000')) {
            $frac = substr($frac, 0, 3);
        } elseif (str_ends_with($frac, '000')) {
            $frac = substr($frac, 0, 6);
        }

        return $sign . $seconds . '.' . $frac . 's';
    }

    /**
     * 4.8: parse a protobuf-JSON duration string into a \DateInterval.
     *
     * Accepts the wire form "[-]<seconds>[.<frac>]s" (e.g. "3600s",
     * "3600.000000001s", "-1.5s"). The whole-seconds part becomes the
     * interval's seconds; the fractional part is right-padded to 9 digits and
     * stored as ->f so the value round-trips through formatProtobufDuration.
     * A leading "-" sets ->invert. Any other shape throws the SDK-owned
     * SerializationException used elsewhere for malformed input.
     *
     * Returns a {@see PreciseDuration} (a \DateInterval subclass) rather than a
     * stock \DateInterval: native ->f truncates sub-microsecond fractions to
     * 0.0, which would silently drop nanosecond durations on parse.
     */
    public static function parseProtobufDuration(string $value): \DateInterval
    {
        if (preg_match('/^(-?)(\d+)(?:\.(\d{1,9}))?s$/', $value, $m) !== 1) {
            throw new SerializationException(
                "Invalid protobuf-JSON duration '$value': "
                . 'expected "<seconds>[.<fraction>]s"'
            );
        }

        /* PHP's \DateInterval::$f stores at most microsecond precision: any
         * value below 1e-6 assigned to it is truncated to 0.0, so a plain
         * \DateInterval cannot round-trip the nanosecond fractions that
         * google.protobuf.Duration allows (e.g. "3600.000000001s"). Build a
         * PreciseDuration instead — a \DateInterval subclass that bypasses the
         * lossy native initialiser and keeps ->f as a full-precision float. */
        $interval = new PreciseDuration();
        $interval->s = (int) $m[2];

        if (isset($m[3])) {
            /* Right-pad the captured fraction to 9 digits (nanoseconds) so the
             * scale is fixed regardless of how many digits were written: ".1"
             * -> "100000000" ns -> 0.1s, ".000000001" -> "000000001" -> 1 ns
             * -> 1.0e-9 s. \d{1,9} guarantees a non-empty capture. */
            $interval->f = (int) str_pad($m[3], 9, '0', STR_PAD_RIGHT) / 1_000_000_000;
        }

        if ($m[1] === '-') {
            $interval->invert = 1;
        }

        return $interval;
    }

    /**
     * Convert a value to a representation suitable for use as a form parameter.
     */
    public static function toFormValue(mixed $value): string
    {
        if ($value instanceof \SplFileObject) {
            return $value->getRealPath();
        }
        return self::stringify($value);
    }
}
